import requests
import json

# Kong Admin API base url
KONG_ADMIN_API = "http://localhost:8001"

# Function to create a Service
def create_service(name, url):
    service_data = {"name": name, "url": url}
    response = requests.post(f"{KONG_ADMIN_API}/services", data=service_data)
    return json.loads(response.text)

# Function to create a Route
def create_route(service_id, paths):
    route_data = {"service.id": service_id, "paths": paths}
    response = requests.post(f"{KONG_ADMIN_API}/services/{service_id}/routes", data=route_data)
    return json.loads(response.text)

# Function to create an Upstream
def create_upstream(name):
    upstream_data = {"name": name}
    response = requests.post(f"{KONG_ADMIN_API}/upstreams", data=upstream_data)
    return json.loads(response.text)

# Function to create a Target
def create_target(upstream_id, target, weight):
    target_data = {"target": target, "weight": weight}
    response = requests.post(f"{KONG_ADMIN_API}/upstreams/{upstream_id}/targets", data=target_data)
    return json.loads(response.text)
    

# Example usage
service = create_service("my-service", "http://my-service:8080")
route = create_route(service['id'], ["/my-service"])
upstream = create_upstream("my-service-upstream")
target = create_target(upstream['id'], "my-service-target:8001", 100)